# Supabase Client-Side React Patterns

Production patterns for using Supabase in React/Next.js **client components**. Focus on performance, avoiding infinite re-renders, and proper data fetching.

## When to Use This Skill

Use when you are:
- Building React components that use Supabase client
- Debugging infinite re-render loops involving Supabase
- Setting up data fetching in client components with `useClient` directive
- Optimizing performance for Supabase queries in the browser

## Core Anti-Patterns to Avoid

### 1. ❌ Creating Client Inside Component Body

```tsx
// WRONG: Creates new instance on every render
"use client"
import { createClient } from '@supabase/supabase-js'

export default function Component() {
  const supabase = createClient()  // ← NEW OBJECT EACH RENDER
  const [data, setData] = useState([])

  useEffect(() => {
    supabase.from('table').select('*').then(...)
  }, [supabase])  // ← DEPENDS ON NEW OBJECT EACH TIME
}
```

**Problem:** `createClient()` returns a new object reference every time. If `useEffect` depends on this reference, it triggers infinitely → React error #310 or silent crashes.

**Fix Options:**

**Option A: Remove from dependency array (simple)**
```tsx
"use client"
import { createClient } from '@supabase/supabase-js'

export default function Component() {
  const supabase = createClient()
  const [data, setData] = useState([])

  useEffect(() => {
    supabase.from('table').select('*').then(...)
  }, [])  // ← EMPTY ARRAY: runs once on mount
}
```

**Option B: Singleton pattern (if same client reused)**
```tsx
// lib/supabase-client.ts
import { createClient } from '@supabase/supabase-js'

export const supabase = createClient()

// Component.tsx
"use client"
import { supabase } from '@/lib/supabase-client'

export default function Component() {
  const [data, setData] = useState([])

  useEffect(() => {
    supabase.from('table').select('*').then(...)
  }, [supabase])  // ← SAFE: stable reference
}
```

### 2. ❌ Forgetting Error Handling

```tsx
// WRONG: Silent failures
useEffect(() => {
  supabase.from('table').select('*').then(({ data }) => {
    if (data) setData(data)
  })
}, [])
```

**Problem:** Network errors, RLS violations, or auth failures cause silent data loss. User sees empty state, no clue why.

**Fix:**
```tsx
useEffect(() => {
  ;(async () => {
    try {
      const { data, error } = await supabase.from('table').select('*')
      if (error) {
        console.error('Supabase query failed:', error)
        // Optional: show user error UI
      } else if (data) {
        setData(data)
      }
    } catch (err) {
      console.error('Exception:', err)
    }
  })()
}, [])
```

### 3. ❌ Loading State Not Handled

```tsx
// WRONG: Flash of empty content or skeleton stuck forever
export default function Product({ slug }: { slug: string }) {
  const [dbLoaded, setDbLoaded] = useState(false)
  const [data, setData] = useState([])

  useEffect(() => {
    supabase.from('table').select('*').then(...)
  }, [])  // ← If this never resolves, setDbLoaded(false) forever
}
```

**Fix: Always set loading state in `finally`**
```tsx
useEffect(() => {
  ;(async () => {
    try {
      const { data, error } = await supabase.from('table').select('*')
      if (error) {
        console.error('Failed:', error)
      } else if (data) {
        setData(data)
      }
    } catch (err) {
      console.error('Exception:', err)
    } finally {
      setDbLoaded(true)  // ← ALWAYS runs, even on error
    }
  })()
}, [])
```

## Recommended Data Fetching Patterns

### Simple Query (one-time fetch)
```tsx
"use client"
import { createClient } from '@supabase/supabase-js'
import { useEffect, useState } from 'react'

export default function Component() {
  const [data, setData] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  useEffect(() => {
    ;(async () => {
      try {
        const { data, error } = await supabase.from('products').select('*')
        if (error) {
          console.error('Fetch failed:', error)
        } else {
          setData(data || [])
        }
      } catch (err) {
        console.error('Exception:', err)
      } finally {
        setLoading(false)
      }
    })()
  }, [])

  if (loading) return <div>Loading...</div>
  return <div>{JSON.stringify(data)}</div>
}
```

### Realtime Subscription
```tsx
"use client"
import { createClient } from '@supabase/supabase-js'
import { useEffect, useState } from 'react'

export default function LiveComponent() {
  const [data, setData] = useState<any[]>([])
  const supabase = createClient()

  useEffect(() => {
    const channel = supabase
      .channel('table-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, (payload) => {
        setData((current) => [...current, payload.new])
      })
      .subscribe()

    return () => supabase.removeChannel(channel)  // ← Cleanup
  }, [supabase])

  return <div>{data.length} items</div>
}
```

### Conditional Fetch (with useMemo)
```tsx
"use client"
import { createClient } from '@supabase/supabase-js'
import { useEffect, useState, useMemo } from 'react'

export default function ProductPage({ slug }: { slug: string }) {
  const [dbProducts, setDbProducts] = useState<any[]>([])
  const [dbLoaded, setDbLoaded] = useState(false)
  const supabase = createClient()

  useEffect(() => {
    ;(async () => {
      try {
        const { data, error } = await supabase.from('products').select('*')
        if (error) {
          console.error('Fetch failed:', error)
        } else {
          setDbProducts(data || [])
        }
      } catch (err) {
        console.error('Exception:', err)
      } finally {
        setDbLoaded(true)
      }
    })()
  }, [])

  // Memoize to avoid recalc on irrelevant re-renders
  const product = useMemo(() => {
    return dbProducts.find(p => slugify(p.name) === slug)
  }, [slug, dbProducts])

  if (!product && dbLoaded) return <div>Not found</div>
  if (!product) return <div>Loading...</div>
  return <div>{product.name}</div>
}
```

## Debugging Checklist

When you see infinite re-renders or loading stuck:

1. **Check useEffect dependencies:**
   ```bash
   grep -r "useEffect.*\[supabase\]" components/
   ```
   If found, remove `supabase` from deps or use singleton pattern.

2. **Check client creation location:**
   ```tsx
   // Component body: ❌
   const supabase = createClient()

   // Module scope: ✓
   export const supabase = createClient()
   ```

3. **Check for missing error handling:**
   ```bash
   grep -r "supabase.from.*select" components/ | grep -v "error\|catch"
   ```
   Should have error handling.

4. **Check loading state:**
   ```tsx
   // Must have finally block
   finally {
     setLoading(false)  // or setDbLoaded(true)
   }
   ```

## Common Error Messages

| Error | Root Cause | Fix |
|-------|-------------|-----|
| React error #310 | useEffect infinite loop | Remove unstable deps, use singleton |
| "Minified React error #310" | Same as above | Same as above |
| Loading skeleton stuck forever | `finally` block missing | Add `finally { setLoaded(true) }` |
| Silent data loss | No error handling | Add `if (error) console.error(...)` |
| Flash of empty content | Race between loading + render | Add explicit `if (loading) return <Skeleton />` |

## Integration with Server Components

**Server component** (metadata, initial data):
```tsx
// app/page.tsx
import { createClient } from '@supabase/supabase-js'
import ProductClient from './product-client'

export default async function Page({ params }: { params: { slug: string } }) {
  const supabase = createClient()
  const { data: product } = await supabase.from('products').select('*').eq('slug', params.slug).single()

  return <ProductClient initialProduct={product} />
}
```

**Client component** (interactivity, realtime):
```tsx
// product-client.tsx
"use client"
import { createClient } from '@supabase/supabase-js'

export default function ProductClient({ initialProduct }: { initialProduct: any }) {
  const [product, setProduct] = useState(initialProduct)
  const supabase = createClient()

  useEffect(() => {
    // Realtime updates here
    const channel = supabase.channel('product-updates')...
    return () => supabase.removeChannel(channel)
  }, [supabase, initialProduct.id])

  return <div>{product.name}</div>
}
```

## Tool-Specific Notes

**@ai-whisperers/auth/supabase:**
- Provides `createClient()` helper that reads env vars automatically
- Safe to use in both client and server components
- No manual token management needed for anon/public queries

**RLS Policies:**
- Client component queries are anon user by default
- Ensure RLS allows `authenticated` or `anon` role to read tables
- Test with `supabase.auth.signIn()` if you need user-specific data

